#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int h[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &h[i]);
        }
        int dp[N];
        dp[0] = 0;
        for (int i = 1; i < N; i++) {
            dp[i] = 1e9;
            for (int j = 0; j < i; j++) {
                if (h[i] - h[j] <= K) {
                    dp[i] = (dp[j] + 1 < dp[i]) ? dp[j] + 1 : dp[i];
                }
            }
        }
        printf("%d\n", dp[N - 1] - 1);
    }
    return 0;
}

