code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] h = new int[N];
            for (int i = 0; i < N; i++) {
                h[i] = sc.nextInt();
            }
            int[] dp = new int[N];
            dp[0] = 0;
            for (int i = 1; i < N; i++) {
                dp[i] = Integer.MAX_VALUE;
                for (int j = 0; j < i; j++) {
                    if (h[i] - h[j] <= K) {
                        dp[i] = Math.min(dp[j] + 1, dp[i]);
                    }
                }
            }
            System.out.println(dp[N - 1] - 1);
        }
    }
}

